form:Form.form:Scripts:
		var CFG,CHLCFG,CTRLLST;
var TIT=null;
var T2T=null;

///////////////////////////////////////////////////////////////////////////////
//EVENTOS
function OnLoad()
{
  //Cargo la Configuracion
  CFG=new NomadXML(Ctrl("main").getResource("QRY_CFG"));
  CHLCFG=new NomadXML(Ctrl("main").getResource("QRY_CHILD"));
  CTRLLST=new NomadXML(Ctrl("main").getResource("QRY_CTRL_LIST"));

  //Modifico los Recursos
  ReplaceResource("QRY_IDS_OBJECT");
  ReplaceResource("QRY_IDS_PARENT");

  //Actualizo el Titulo
  if ((Ctrl("PAR"))&& (CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
  {
    if (TIT==null)
      TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

    while(TIT!=null)
    {
      if (TIT.GetAttr("descr")!="")
        Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
      TIT=TIT.FirstChild();
    }
  }

  if ((Ctrl("OBJ"))&& (CFG.GetAttr("RESOURCE-OBJECT")!="") && (Ctrl("ID").GetXValue()!=""))
  {
    if (T2T==null)
      T2T=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_OBJECT"), '<PARAM IDS="'+Ctrl("ID").GetXValue()+'"/>');

    while(T2T!=null)
    {
      if (T2T.GetAttr("descr")!="")
        Ctrl("OBJ").SetXValue(" '"+T2T.GetAttr("descr")+"'");
      T2T=T2T.FirstChild();
    }
  }

  if (Ctrl("HiLockREG").GetXValue()!="0" && Ctrl("HiLockREG").GetXValue()!="")
  {
    CtrlEnabled("EDIT"  ,0);
    CtrlEnabled("DELETE",0);
  } else
  {
    CtrlEnabled("EDIT"  ,CheckEnabledButton("EDIT"));
    CtrlEnabled("DELETE",CheckEnabledButton("DELETE"));
  }

  for(cur=CTRLLST.FirstChild(); cur!=null; cur=cur.Next())
    ListViewEnabledButton(Ctrl(cur.GetAttr("name")));

  //Evento PosONLOAD
  PosOnLoad();
}

function PosOnLoad()
{
}

function CheckEnabledButton(name)
{
	return true;
}

function ReplaceResource(recID)
{
  var recValue=Ctrl("main").getResource(recID);
  recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
  recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"  ));

  Ctrl("main").setResource(recValue, recID);
}

function DependCall(obj)
{
  var flowId=CHLCFG.FindElement2("CHILD","name",obj.ID()).GetAttr("flow");
  var flag  =CHLCFG.FindElement2("CHILD","name",obj.ID()).GetAttr("flag");

  if (flowId.indexOf(":")>=0)
    appendFormInMain(flowId.split(":")[0], flowId.split(":")[1], '<DATA PARENT="'+Ctrl("ID").GetXValue()+'" GRAND="'+Ctrl("PARENT").GetXValue()+'" />');
  else
    appendFormInMain(flowId              , "LIST"              , '<DATA PARENT="'+Ctrl("ID").GetXValue()+'" GRAND="'+Ctrl("PARENT").GetXValue()+'" />');
}

function CallListViewButton(obj)
{
  var MyID=obj.ID().substr(obj.m_Parent.ID().length+1);

  var flowId=CHLCFG.FindElement2("CHILD","name",MyID).GetAttr("flow");
  var flag  =CHLCFG.FindElement2("CHILD","name",MyID).GetAttr("flag");

  if (flowId.indexOf(":")>=0)
    appendFormInMain(flowId.split(":")[0], flowId.split(":")[1], '<DATA LIST="'+obj.m_Parent.GetXValue()+'" PARENT="'+Ctrl("ID").GetXValue()+'" GRAND="'+Ctrl("PARENT").GetXValue()+'" />');
  else
    appendFormInMain(flowId              , "LIST"              , '<DATA LIST="'+obj.m_Parent.GetXValue()+'" PARENT="'+Ctrl("ID").GetXValue()+'" GRAND="'+Ctrl("PARENT").GetXValue()+'" />');
}

function ListViewEnabledButton(obj)
{
  if (obj==null) return;
  var t,f;
  var objc;
  var MyID;
  var cCFG;

  for (t=0; t<obj.m_Children.length; t++)
  {
    objc=obj.m_Children[t];

    MyID=objc.ID().substr(obj.ID().length+1);

    cCFG=CHLCFG.FindElement2("CHILD","name",MyID);
    if (cCFG==null) continue;

    f=cCFG.GetAttrInt("flag");

    if (obj.GetXValue()=="" || obj.TotalRow<=0)
    {
      CtrlEnabled(objc.ID(), (f==2?CheckEnabledButton(objc.ID()):false));
    } else
    if (obj.GetSelectAttrValue("lock")!="")
    {
      CtrlEnabled(objc.ID(), (f==2?CheckEnabledButton(objc.ID()):false));
    } else
    {
      CtrlEnabled(objc.ID(), CheckEnabledButton(objc.ID()));
    }
  }
}

function OnRefresh()
{
  NomadTimeout("InternalRefresh();", 200, "Actualizando...");
}

function InternalRefresh()
{
  Ctrl("main").DoEvent("REFRESH");
}
